record.field:
for property in records:
    if meter_readings := property.x_meter_reading_ids.filtered(lambda l: not l.x_invoice_id and l.x_usage > 0):
        invoice = env['account.move'].create({
            'move_type': 'out_invoice',
            'partner_id': property.x_rental_contract_id.partner_id.id,
        })
        for meter_reading in meter_readings:
            env['account.move.line'].create({
                'move_id': invoice.id,
                'price_unit': meter_reading.x_meter_id.x_price,
                'name': str(meter_reading.x_date) + ' - ' + meter_reading.x_description if meter_reading.x_description else meter_reading.x_date,
                'quantity' : meter_reading.x_usage,
                'x_property_id': property.id,
            })
        meter_readings['x_invoice_id'] = invoice.id
        action = env['ir.actions.act_window']._for_xml_id('account.action_move_out_invoice_type')
        action['views'] = [(env.ref('account.view_move_form').id, 'form')]
        action['res_id'] = invoice.id

action = env['ir.actions.act_window']._for_xml_id('sale.action_orders')
action['domain'] = [('x_property_id', 'in', records.ids), ('is_subscription', '=', True)]
action['context'] = {'default_is_subscription': True}

for order in record:
    stake_holder = env['x_stake_holder'].create({
        'x_stake_holder': order.partner_id.id,
        'x_property_id': order.x_property_id.id,
        'x_start_date': order.start_date,
        'x_end_date': order.end_date,
        'x_type': 'tenant',
    })
